function DECODE_IMAGE(stego_image_path):
 # Load stego-image
 stego_image = LOAD_IMAGE(stego_image_path)
 pixels = GET_PIXEL_ARRAY(stego_image)

 # Extract LSB bits
 extracted_bits = ""
 for i in range(len(pixels)):
 for channel in [RED, GREEN, BLUE]:
 pixel_value = pixels[i][channel]
 lsb = pixel_value & 1 # Get LSB
 extracted_bits = extracted_bits + str(lsb)

 # Check for end marker (8 consecutive zeros)
 if len(extracted_bits) >= 8:
 recent_bits = extracted_bits[-8:]
 if recent_bits == "00000000":
 # End marker found
 binary_message = extracted_bits[:-8]
 return BINARY_TO_STRING(binary_message)

 # If no end marker, return whatever was extracted
 return BINARY_TO_STRING(extracted_bits)
